  1→use crate::dicom::DicomTag;
  2→use crate::validation::{SopClass, ValidationResult};
  3→use crossterm::event::{self, Event, KeyCode, KeyEventKind, MouseButton, MouseEventKind};
  4→use ratatui::layout::Rect;
  5→use ratatui::widgets::TableState;
  6→use ratatui_image::picker::Picker;
  7→use ratatui_image::protocol::StatefulProtocol;
  8→use std::io;
  9→use std::path::PathBuf;
 10→
 11→/// Application state
 12→pub struct App {
 13→    /// Visible tags to display (flattened based on expansion state)
 14→    pub tags: Vec<DicomTag>,
 15→    /// All unfiltered DICOM tags (hierarchical)
 16→    pub all_tags: Vec<DicomTag>,
 17→    /// Filtered top-level tags when search is active (hierarchical, preserves children)
 18→    filtered_tags: Option<Vec<DicomTag>>,
 19→    /// Table state for tracking selection/scroll position
 20→    pub table_state: TableState,
 21→    /// Whether the application should quit
 22→    pub should_quit: bool,
 23→    /// The file name being viewed (or baseline name in diff mode)
 24→    pub file_name: String,
 25→    /// Whether diff mode is active
 26→    pub diff_mode: bool,
 27→    /// Modified file name in diff mode
 28→    pub modified_name: Option<String>,
 29→    /// Whether search mode is active
 30→    pub search_mode: bool,
 31→    /// Current search query
 32→    pub search_query: String,
 33→    /// Type 1 field validation result
 34→    pub validation_result: ValidationResult,
 35→    /// SOP Class interpretation
 36→    pub sop_class: SopClass,
 37→    pub table_area: Rect,
 38→    pub show_preview: bool,
 39→    pub preview_image: Option<StatefulProtocol>,
 40→    pub preview_error: Option<String>,
 41→    pub dicom_file_path: Option<PathBuf>,
 42→    pub picker: Option<Picker>,
 43→}
 44→
 45→impl App {
 46→    pub fn new_with_diff(
 47→        tags: Vec<DicomTag>,
 48→        file_name: String,
 49→        modified_name: Option<String>,
 50→        validation_result: ValidationResult,
 51→        sop_class: SopClass,
 52→        diff_mode: bool,
 53→        dicom_file_path: Option<PathBuf>,
 54→        picker: Option<Picker>,
 55→    ) -> Self {
 56→        let mut table_state = TableState::default();
 57→        let visible_tags = Self::build_visible_tags_from(&tags);
 58→        if !visible_tags.is_empty() {
 59→            table_state.select(Some(0));
 60→        }
 61→
 62→        let mut app = Self {
 63→            tags: visible_tags,
 64→            all_tags: tags,
 65→            filtered_tags: None,
 66→            table_state,
 67→            should_quit: false,
 68→            file_name,
 69→            diff_mode,
 70→            modified_name,
 71→            search_mode: false,
 72→            search_query: String::new(),
 73→            validation_result,
 74→            sop_class,
 75→            table_area: Rect::default(),
 76→            show_preview: true,
 77→            preview_image: None,
 78→            preview_error: None,
 79→            dicom_file_path,
 80→            picker,
 81→        };
 82→        app.decode_preview();
 83→        app
 84→    }
 85→
 86→    fn build_visible_tags_from(tags: &[DicomTag]) -> Vec<DicomTag> {
 87→        let mut visible = Vec::new();
 88→        Self::collect_visible_tags(tags, &mut visible);
 89→        visible
 90→    }
 91→
 92→    fn collect_visible_tags(tags: &[DicomTag], visible: &mut Vec<DicomTag>) {
 93→        for tag in tags {
 94→            visible.push(tag.clone());
 95→            if tag.is_expanded && !tag.children.is_empty() {
 96→                Self::collect_visible_tags(&tag.children, visible);
 97→            }
 98→        }
 99→    }
100→
101→    fn rebuild_visible_tags(&mut self) {
102→        // Use filtered_tags if a search filter is active, otherwise use all_tags
103→        let source = self.filtered_tags.as_ref().unwrap_or(&self.all_tags);
104→        self.tags = Self::build_visible_tags_from(source);
105→    }
106→
107→    /// Returns the hierarchical tag source for path operations
108→    fn active_tags(&self) -> &Vec<DicomTag> {
109→        self.filtered_tags.as_ref().unwrap_or(&self.all_tags)
110→    }
111→
112→    /// Returns mutable hierarchical tag source for modifications
113→    fn active_tags_mut(&mut self) -> &mut Vec<DicomTag> {
114→        if self.filtered_tags.is_some() {
115→            self.filtered_tags.as_mut().unwrap()
116→        } else {
117→            &mut self.all_tags
118→        }
119→    }
120→
121→    fn expand_selected(&mut self) {
122→        if let Some(selected_idx) = self.table_state.selected() {
123→            if selected_idx < self.tags.len() {
124→                let selected_tag = &self.tags[selected_idx];
125→                if selected_tag.is_expandable && !selected_tag.is_expanded {
126→                    let path = self.build_path_to_tag(selected_idx);
127→                    Self::set_expanded_in_tree(self.active_tags_mut(), &path, true);
128→                    self.rebuild_visible_tags();
129→                }
130→            }
131→        }
132→    }
133→
134→    fn collapse_parent(&mut self) {
135→        if let Some(selected_idx) = self.table_state.selected() {
136→            if selected_idx < self.tags.len() {
137→                let current_depth = self.tags[selected_idx].depth;
138→
139→                if current_depth > 0 {
140→                    for i in (0..selected_idx).rev() {
141→                        if self.tags[i].depth < current_depth && self.tags[i].is_expanded {
142→                            let path = self.build_path_to_tag(i);
143→                            Self::set_expanded_in_tree(self.active_tags_mut(), &path, false);
144→                            self.rebuild_visible_tags();
145→                            self.table_state.select(Some(i));
146→                            break;
147→                        }
148→                    }
149→                }
150→            }
151→        }
152→    }
153→
154→    fn build_path_to_tag(&self, visible_idx: usize) -> Vec<usize> {
155→        let mut path = Vec::new();
156→        let mut current_idx = 0;
157→        Self::find_path_to_index(self.active_tags(), visible_idx, &mut current_idx, &mut path);
158→        path
159→    }
160→
161→    fn find_path_to_index(
162→        tags: &[DicomTag],
163→        target_idx: usize,
164→        current_idx: &mut usize,
165→        path: &mut Vec<usize>,
166→    ) -> bool {
167→        for (i, tag) in tags.iter().enumerate() {
168→            if *current_idx == target_idx {
169→                path.push(i);
170→                return true;
171→            }
172→            *current_idx += 1;
173→
174→            if tag.is_expanded && !tag.children.is_empty() {
175→                path.push(i);
176→                if Self::find_path_to_index(&tag.children, target_idx, current_idx, path) {
177→                    return true;
178→                }
179→                path.pop();
180→            }
181→        }
182→        false
183→    }
184→
185→    fn set_expanded_in_tree(tags: &mut [DicomTag], path: &[usize], expanded: bool) {
186→        if path.is_empty() {
187→            return;
188→        }
189→
190→        let idx = path[0];
191→        if idx >= tags.len() {
192→            return;
193→        }
194→
195→        if path.len() == 1 {
196→            tags[idx].is_expanded = expanded;
197→        } else {
198→            Self::set_expanded_in_tree(&mut tags[idx].children, &path[1..], expanded);
199→        }
200→    }
201→
202→    pub fn handle_events(&mut self) -> io::Result<()> {
203→        if event::poll(std::time::Duration::from_millis(100))? {
204→            match event::read()? {
205→                Event::Key(key) if key.kind == KeyEventKind::Press => {
206→                    if self.search_mode {
207→                        match key.code {
208→                            KeyCode::Esc => {
209→                                self.search_mode = false;
210→                                self.search_query.clear();
211→                                self.filtered_tags = None;
212→                                self.rebuild_visible_tags();
213→                                self.reset_selection();
214→                            }
215→                            KeyCode::Enter => {
216→                                self.search_mode = false;
217→                            }
218→                            KeyCode::Backspace => {
219→                                self.search_query.pop();
220→                                self.filter_tags();
221→                            }
222→                            KeyCode::Char(c) => {
223→                                self.search_query.push(c);
224→                                self.filter_tags();
225→                            }
226→                            _ => {}
227→                        }
228→                    } else {
229→                        match key.code {
230→                            KeyCode::Char('q') | KeyCode::Esc => {
231→                                if self.search_query == "" {
232→                                    self.should_quit = true;
233→                                } else {
234→                                    self.search_query.clear();
235→                                    self.filtered_tags = None;
236→                                    self.rebuild_visible_tags();
237→                                    self.reset_selection();
238→                                }
239→                            }
240→                            KeyCode::Down | KeyCode::Char('j') => {
241→                                self.scroll_down(1);
242→                            }
243→                            KeyCode::Up | KeyCode::Char('k') => {
244→                                self.scroll_up(1);
245→                            }
246→                            KeyCode::Char('/') => {
247→                                self.search_mode = true;
248→                            }
249→                            KeyCode::Char('p') => {
250→                                self.toggle_preview();
251→                            }
252→                            KeyCode::Right | KeyCode::Char('l') => {
253→                                self.expand_selected();
254→                            }
255→                            KeyCode::Left | KeyCode::Char('h') => {
256→                                self.collapse_parent();
257→                            }
258→                            _ => {}
259→                        }
260→                    }
261→                }
262→                Event::Mouse(mouse) => match mouse.kind {
263→                    MouseEventKind::ScrollDown => self.scroll_down(3),
264→                    MouseEventKind::ScrollUp => self.scroll_up(3),
265→                    MouseEventKind::Down(MouseButton::Left) => {
266→                        let y = mouse.row;
267→                        if y > self.table_area.y + 1
268→                            && y < self.table_area.y + self.table_area.height
269→                        {
270→                            let row_in_viewport = (y - self.table_area.y - 2) as usize;
271→                            let tag_index = self.table_state.offset() + row_in_viewport;
272→                            if tag_index < self.tags.len() {
273→                                self.table_state.select(Some(tag_index));
274→                            }
275→                        }
276→                    }
277→                    _ => {}
278→                },
279→                _ => {}
280→            }
281→        }
282→        Ok(())
283→    }
284→
285→    fn scroll_down(&mut self, amount: usize) {
286→        if self.tags.is_empty() {
287→            return;
288→        }
289→
290→        let current = self.table_state.selected().unwrap_or(0);
291→        let max_index = self.tags.len().saturating_sub(1);
292→        let new_index = (current + amount).min(max_index);
293→        self.table_state.select(Some(new_index));
294→    }
295→
296→    fn scroll_up(&mut self, amount: usize) {
297→        if self.tags.is_empty() {
298→            return;
299→        }
300→
301→        let current = self.table_state.selected().unwrap_or(0);
302→        let new_index = current.saturating_sub(amount);
303→        self.table_state.select(Some(new_index));
304→    }
305→
306→    fn filter_tags(&mut self) {
307→        if self.search_query.is_empty() {
308→            self.filtered_tags = None;
309→            self.rebuild_visible_tags();
310→        } else {
311→            let query = self.search_query.to_lowercase();
312→            // Filter top-level tags but preserve their full hierarchy (children)
313→            let filtered: Vec<DicomTag> = self
314→                .all_tags
315→                .iter()
316→                .filter(|tag| {
317→                    tag.tag.to_lowercase().contains(&query)
318→                        || tag.name.to_lowercase().contains(&query)
319→                })
320→                .cloned()
321→                .collect();
322→            self.filtered_tags = Some(filtered);
323→            self.rebuild_visible_tags();
324→        }
325→        self.reset_selection();
326→    }
327→
328→    fn reset_selection(&mut self) {
329→        if self.tags.is_empty() {
330→            self.table_state.select(None);
331→        } else {
332→            self.table_state.select(Some(0));
333→        }
334→    }
335→
336→    fn toggle_preview(&mut self) {
337→        self.show_preview = !self.show_preview;
338→
339→        if self.show_preview && self.preview_image.is_none() && self.preview_error.is_none() {
340→            self.decode_preview();
341→        }
342→    }
343→
344→    fn decode_preview(&mut self) {
345→        use dicom_pixeldata::PixelDecoder;
346→        use ratatui_image::picker::ProtocolType;
347→
348→        let Some(picker) = &self.picker else {
349→            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
350→            return;
351→        };
352→
353→        if picker.protocol_type() != ProtocolType::Kitty {
354→            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
355→            return;
356→        }
357→
358→        let Some(path) = &self.dicom_file_path else {
359→            self.preview_error = Some("No DICOM file path available".into());
360→            return;
361→        };
362→
363→        let obj = match dicom::object::open_file(path) {
364→            Ok(obj) => obj,
365→            Err(e) => {
366→                self.preview_error = Some(format!("Failed to open DICOM file: {}", e));
367→                return;
368→            }
369→        };
370→
371→        let pixel_data = match obj.decode_pixel_data() {
372→            Ok(pd) => pd,
373→            Err(e) => {
374→                self.preview_error = Some(format!("Failed to decode pixel data: {}", e));
375→                return;
376→            }
377→        };
378→
379→        let dyn_img = match pixel_data.to_dynamic_image(0) {
380→            Ok(img) => img,
381→            Err(e) => {
382→                self.preview_error = Some(format!("Failed to convert to image: {}", e));
383→                return;
384→            }
385→        };
386→
387→        let mut picker = self.picker.take().unwrap();
388→        self.preview_image = Some(picker.new_resize_protocol(dyn_img));
389→        self.picker = Some(picker);
390→    }
391→}
