 10→/// Status of a tag in diff mode
 11→#[derive(Clone, Debug, PartialEq)]
 12→pub enum DiffStatus {
 13→    Unchanged,
 14→    Added,   // In modified but not baseline
 15→    Deleted, // In baseline but not modified
 16→    Changed, // Same tag, different value
 17→}
 18→
 19→/// Represents a single DICOM tag with its properties
 20→#[derive(Clone, Debug)]
 21→pub struct DicomTag {
 22→    /// Tag in (GGGG,EEEE) hex format
 23→    pub tag: String,
 24→    /// Human-readable tag name
 25→    pub name: String,
 26→    /// Value Representation (e.g., "PN", "CS", "LO")
 27→    pub vr: String,
 28→    /// The tag value, truncated if longer than 256 characters
 29→    pub value: String,
 30→    /// Baseline value for changed tags in diff mode (None otherwise)
 31→    pub baseline_value: Option<String>,
 32→    /// Nesting level (0 = root)
 33→    pub depth: usize,
 34→    /// True if this tag has children (is a sequence)
 35→    pub is_expandable: bool,
 36→    /// Current expansion state
 37→    pub is_expanded: bool,
 38→    /// Nested sequence items
 39→    pub children: Vec<DicomTag>,
 40→    /// Diff status (None in normal mode, Some(status) in diff mode)
 41→    pub diff_status: Option<DiffStatus>,
 42→}
 43→
 44→impl DicomTag {
 45→    pub fn is_private(&self) -> bool {
 46→        self.tag
 47→            .get(1..5)
 48→            .and_then(|s| u16::from_str_radix(s, 16).ok())
 49→            .map(|group| group % 2 == 1)
 50→            .unwrap_or(false)
 51→    }
 52→}
