118→fn extract_tags(obj: &FileDicomObject<InMemDicomObject>) -> Vec<DicomTag> {
119→    let mut tags = Vec::new();
120→
121→    for element in obj.meta().to_element_iter() {
122→        let tag = element.tag();
123→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
124→
125→        let name = StandardDataDictionary
126→            .by_tag(tag)
127→            .map(|entry| entry.alias.to_string())
128→            .unwrap_or_default();
129→
130→        let vr = element.vr().to_string();
131→        let value = format_value(element.value());
132→
133→        tags.push(DicomTag {
134→            tag: tag_str,
135→            name,
136→            vr: vr.to_string(),
137→            value,
138→            baseline_value: None,
139→            depth: 0,
140→            is_expandable: false,
141→            is_expanded: false,
142→            children: Vec::new(),
143→            diff_status: None,
144→        });
145→    }
146→
147→    for element in obj {
148→        let tag = element.tag();
149→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
150→
151→        let name = StandardDataDictionary
152→            .by_tag(tag)
153→            .map(|entry| entry.alias.to_string())
154→            .unwrap_or_default();
155→
156→        let vr = element.vr().to_string();
157→
158→        let (value, children, is_expandable) = if let Some(items) = element.value().items() {
159→            let children = extract_sequence_items(items, 1);
160→            let is_expandable = !children.is_empty();
161→            let value = format!("<Sequence with {} item(s)>", items.len());
162→            (value, children, is_expandable)
163→        } else {
164→            (format_value(element.value()), Vec::new(), false)
165→        };
166→
167→        tags.push(DicomTag {
168→            tag: tag_str,
169→            name,
170→            vr: vr.to_string(),
171→            value,
172→            baseline_value: None,
173→            depth: 0,
174→            is_expandable,
175→            is_expanded: false,
176→            children,
177→            diff_status: None,
178→        });
179→    }
180→
181→    tags
182→}
