222→            let children = extract_sequence_items(items, depth + 1);
223→            let is_expandable = !children.is_empty();
224→            let value = format!("<Sequence with {} item(s)>", items.len());
225→            (value, children, is_expandable)
226→        } else {
227→            (format_value(element.value()), Vec::new(), false)
228→        };
229→
230→        tags.push(DicomTag {
231→            tag: tag_str,
232→            name,
233→            vr: vr.to_string(),
234→            value,
235→            baseline_value: None,
236→            depth,
237→            is_expandable,
238→            is_expanded: false,
239→            children,
240→            diff_status: None,
241→        });
242→    }
243→
244→    tags
