273→                    MouseEventKind::ScrollUp => self.scroll_up(3),
274→                    MouseEventKind::Down(MouseButton::Left) => {
275→                        let y = mouse.row;
276→                        if y > self.table_area.y + 1
277→                            && y < self.table_area.y + self.table_area.height
278→                        {
279→                            let row_in_viewport = (y - self.table_area.y - 2) as usize;
280→                            let tag_index = self.table_state.offset() + row_in_viewport;
281→                            if tag_index < self.tags.len() {
282→                                self.table_state.select(Some(tag_index));
283→                            }
284→                        }
