297→        }
298→
299→        let current = self.table_state.selected().unwrap_or(0);
300→        let max_index = self.tags.len().saturating_sub(1);
301→        let new_index = (current + amount).min(max_index);
302→        self.table_state.select(Some(new_index));
303→    }
304→
305→    fn scroll_up(&mut self, amount: usize) {
306→        if self.tags.is_empty() {
307→            return;
308→        }
309→
310→        let current = self.table_state.selected().unwrap_or(0);
311→        let new_index = current.saturating_sub(amount);
312→        self.table_state.select(Some(new_index));
313→    }
