315→    fn filter_tags(&mut self) {
316→        if self.search_query.is_empty() {
317→            self.filtered_tags = None;
318→            self.rebuild_visible_tags();
319→        } else {
320→            let query = self.search_query.to_lowercase();
321→            // Filter top-level tags but preserve their full hierarchy (children)
322→            let filtered: Vec<DicomTag> = self
323→                .all_tags
324→                .iter()
325→                .filter(|tag| {
326→                    tag.tag.to_lowercase().contains(&query)
327→                        || tag.name.to_lowercase().contains(&query)
328→                })
329→                .cloned()
330→                .collect();
331→            self.filtered_tags = Some(filtered);
332→            self.rebuild_visible_tags();
333→        }
334→        self.reset_selection();
335→    }
336→
337→    fn reset_selection(&mut self) {
338→        if self.tags.is_empty() {
339→            self.table_state.select(None);
340→        } else {
341→            self.table_state.select(Some(0));
342→        }
343→    }
344→
345→    fn toggle_preview(&mut self) {
346→        self.show_preview = !self.show_preview;
347→
348→        if self.show_preview && self.preview_image.is_none() && self.preview_error.is_none() {
349→            self.decode_preview();
350→        }
351→    }
352→
353→    fn decode_preview(&mut self) {
354→        use dicom_pixeldata::PixelDecoder;
355→        use ratatui_image::picker::ProtocolType;
356→
357→        let Some(picker) = &self.picker else {
358→            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
359→            return;
360→        };
361→
362→        if picker.protocol_type() != ProtocolType::Kitty {
363→            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
364→            return;
365→        }
366→
367→        let Some(path) = &self.dicom_file_path else {
368→            self.preview_error = Some("No DICOM file path available".into());
369→            return;
370→        };
371→
372→        let obj = match dicom::object::open_file(path) {
373→            Ok(obj) => obj,
374→            Err(e) => {
375→                self.preview_error = Some(format!("Failed to open DICOM file: {}", e));
376→                return;
377→            }
378→        };
379→
380→        let pixel_data = match obj.decode_pixel_data() {
381→            Ok(pd) => pd,
382→            Err(e) => {
383→                self.preview_error = Some(format!("Failed to decode pixel data: {}", e));
384→                return;
385→            }
386→        };
387→
388→        let dyn_img = match pixel_data.to_dynamic_image(0) {
389→            Ok(img) => img,
390→            Err(e) => {
391→                self.preview_error = Some(format!("Failed to convert to image: {}", e));
392→                return;
393→            }
394→        };
395→
396→        let mut picker = self.picker.take().unwrap();
397→        self.preview_image = Some(picker.new_resize_protocol(dyn_img));
398→        self.picker = Some(picker);
399→    }
400→}
