  2→use std::io;
  3→
  4→use super::App;
  5→
  6→impl App {
  7→    pub fn handle_events(&mut self) -> io::Result<()> {
  8→        if event::poll(std::time::Duration::from_millis(100))? {
  9→            match event::read()? {
 10→                Event::Key(key) if key.kind == KeyEventKind::Press => {
 11→                    if self.search_mode {
 12→                        match key.code {
 13→                            KeyCode::Esc => {
 14→                                self.search_mode = false;
 15→                                self.search_query.clear();
 16→                                self.filtered_tags = None;
 17→                                self.rebuild_visible_tags();
 18→                                self.reset_selection();
 19→                            }
 20→                            KeyCode::Enter => {
 21→                                self.search_mode = false;
 22→                            }
 23→                            KeyCode::Backspace => {
 24→                                self.search_query.pop();
 25→                                self.filter_tags();
 26→                            }
 27→                            KeyCode::Char(c) => {
 28→                                self.search_query.push(c);
 29→                                self.filter_tags();
 30→                            }
 31→                            _ => {}
 32→                        }
 33→                    } else {
 34→                        match key.code {
 35→                            KeyCode::Char('q') | KeyCode::Esc => {
 36→                                if self.search_query.is_empty() {
 37→                                    self.should_quit = true;
 38→                                } else {
 39→                                    self.search_query.clear();
 40→                                    self.filtered_tags = None;
 41→                                    self.rebuild_visible_tags();
 42→                                    self.reset_selection();
 43→                                }
 44→                            }
 45→                            KeyCode::Down | KeyCode::Char('j') => {
 46→                                self.scroll_down(1);
 47→                            }
 48→                            KeyCode::Up | KeyCode::Char('k') => {
 49→                                self.scroll_up(1);
 50→                            }
 51→                            KeyCode::Char('/') => {
 52→                                self.search_mode = true;
 53→                            }
 54→                            KeyCode::Char('p') => {
 55→                                self.toggle_preview();
 56→                            }
 57→                            KeyCode::Right | KeyCode::Char('l') => {
 58→                                self.expand_selected();
 59→                            }
 60→                            KeyCode::Left | KeyCode::Char('h') => {
 61→                                self.collapse_parent();
 62→                            }
 63→                            _ => {}
 64→                        }
 65→                    }
 66→                }
 67→                Event::Mouse(mouse) => match mouse.kind {
 68→                    MouseEventKind::ScrollDown => self.scroll_down(3),
 69→                    MouseEventKind::ScrollUp => self.scroll_up(3),
 70→                    MouseEventKind::Down(MouseButton::Left) => {
 71→                        let y = mouse.row;
 72→                        if y > self.table_area.y + 1
 73→                            && y < self.table_area.y + self.table_area.height
 74→                        {
 75→                            let row_in_viewport = (y - self.table_area.y - 2) as usize;
 76→                            let tag_index = self.table_state.offset() + row_in_viewport;
 77→                            if tag_index < self.tags.len() {
 78→                                self.table_state.select(Some(tag_index));
 79→                            }
 80→                        }
 81→                    }
 82→                    _ => {}
 83→                },
 84→                _ => {}
 85→            }
 86→        }
 87→        Ok(())
 88→    }
 89→
 90→    pub(super) fn scroll_down(&mut self, amount: usize) {
 91→        if self.tags.is_empty() {
 92→            return;
 93→        }
 94→
 95→        let current = self.table_state.selected().unwrap_or(0);
 96→        let max_index = self.tags.len().saturating_sub(1);
 97→        let new_index = (current + amount).min(max_index);
 98→        self.table_state.select(Some(new_index));
 99→    }
100→
101→    pub(super) fn scroll_up(&mut self, amount: usize) {
102→        if self.tags.is_empty() {
103→            return;
104→        }
105→
106→        let current = self.table_state.selected().unwrap_or(0);
107→        let new_index = current.saturating_sub(amount);
108→        self.table_state.select(Some(new_index));
109→    }
110→}
