 9→pub fn validate_type1_fields<P: AsRef<Path>>(
10→    path: P,
11→) -> Result<ValidationResult, Box<dyn std::error::Error>> {
12→    let obj = open_file(path)?;
13→    Ok(validate_type1_fields_from_obj(&obj))
14→}
15→
16→pub fn validate_type1_fields_from_obj(obj: &FileDicomObject<InMemDicomObject>) -> ValidationResult {
17→    let sop_class_uid = obj
18→        .element(tags::SOP_CLASS_UID)
19→        .ok()
20→        .and_then(|e| e.to_str().ok())
21→        .map(|s| s.trim().to_string());
22→
23→    let sop_class_uid = match sop_class_uid {
24→        Some(uid) => uid,
25→        None => return ValidationResult::NotApplicable,
26→    };
27→
28→    let modality_tags: &[(Tag, &str)] = if sop_class_uid == CT_IMAGE_STORAGE {
29→        CT_IMAGE_TYPE1_TAGS
30→    } else if sop_class_uid == MR_IMAGE_STORAGE {
31→        MR_IMAGE_TYPE1_TAGS
32→    } else {
33→        return ValidationResult::NotApplicable;
34→    };
35→
36→    let mut missing_tags = Vec::new();
37→
38→    let all_tag_groups: &[&[(Tag, &str)]] = &[
39→        SOP_COMMON_TYPE1_TAGS,
40→        GENERAL_STUDY_TYPE1_TAGS,
41→        GENERAL_SERIES_TYPE1_TAGS,
42→        FRAME_OF_REFERENCE_TYPE1_TAGS,
43→        IMAGE_PLANE_TYPE1_TAGS,
44→        IMAGE_PIXEL_TYPE1_TAGS,
45→        modality_tags,
46→    ];
47→
48→    for group in all_tag_groups {
49→        for (tag, name) in *group {
50→            if !is_tag_present(obj, *tag) {
51→                missing_tags.push(name.to_string());
52→            }
53→        }
54→    }
55→
56→    if missing_tags.is_empty() {
57→        ValidationResult::Valid
58→    } else {
59→        ValidationResult::Invalid(missing_tags)
60→    }
61→}
62→
63→fn is_tag_present(obj: &FileDicomObject<InMemDicomObject>, tag: Tag) -> bool {
64→    obj.element(tag)
65→        .ok()
66→        .map(|e| {
67→            if let Ok(s) = e.to_str() {
68→                !s.trim().is_empty()
69→            } else {
70→                true
71→            }
72→        })
73→        .unwrap_or(false)
74→}
