83→pub fn get_sop_class_from_obj(obj: &FileDicomObject<InMemDicomObject>) -> SopClass {
84→    let sop_class_uid = obj
85→        .element(tags::SOP_CLASS_UID)
86→        .ok()
87→        .and_then(|e| e.to_str().ok())
88→        .map(|s| s.trim().to_string());
89→
90→    match sop_class_uid {
91→        Some(uid) if uid == CT_IMAGE_STORAGE => SopClass::Ct,
92→        Some(uid) if uid == MR_IMAGE_STORAGE => SopClass::Mr,
93→        Some(uid) => SopClass::Other(uid),
94→        None => SopClass::Unknown,
95→    }
