181→            Constraint::Fill(1),
182→        ]
183→    } else {
184→        vec![
185→            Constraint::Length(16),
186→            Constraint::Length(36),
187→            Constraint::Length(4),
188→            Constraint::Fill(1),
189→        ]
190→    };
191→
192→    let title = if app.diff_mode {
193→        if let Some(ref modified_name) = app.modified_name {
194→            format!(" DICOM Diff: {} ↔ {} ", app.file_name, modified_name)
195→        } else {
196→            format!(" DICOM Diff: {} ", app.file_name)
197→        }
198→    } else {
199→        format!(" DICOM Viewer: {} ", app.file_name)
200→    };
201→
202→    let table = Table::new(rows, widths)
203→        .header(header)
204→        .block(Block::default().borders(Borders::ALL).title(title))
205→        .row_highlight_style(
206→            Style::default()
207→                .bg(Color::DarkGray)
208→                .add_modifier(Modifier::BOLD),
209→        );
210→
211→    app.table_area = area;
212→    frame.render_stateful_widget(table, area, &mut app.table_state);
213→
214→    render_help(frame, area, app);
215→}
216→
217→fn render_inline_diff(baseline: &str, modified: &str) -> Line<'static> {
218→    let diff = TextDiff::from_words(baseline, modified);
219→    let mut spans = Vec::new();
220→
221→    for change in diff.iter_all_changes() {
222→        let text = change.value();
223→        let style = match change.tag() {
224→            ChangeTag::Delete => Style::default()
225→                .fg(Color::Red)
226→                .bg(Color::DarkGray)
227→                .add_modifier(Modifier::CROSSED_OUT),
228→            ChangeTag::Insert => Style::default()
229→                .fg(Color::Green)
230→                .add_modifier(Modifier::BOLD),
231→            ChangeTag::Equal => Style::default(),
232→        };
233→        spans.push(Span::styled(text.to_string(), style));
234→    }
235→
236→    Line::from(spans)
237→}
