239→fn render_help(frame: &mut Frame, area: Rect, app: &App) {
240→    let help_area = Rect {
241→        x: area.x + 1,
242→        y: area.y + area.height.saturating_sub(1),
243→        width: area.width.saturating_sub(2),
244→        height: 1,
245→    };
246→
247→    if app.search_mode {
248→        let search_text = format!("/{}_", app.search_query);
249→        let search = Paragraph::new(search_text).style(Style::default().fg(Color::Yellow));
250→        frame.render_widget(search, help_area);
251→    } else {
252→        let help_text = " ↑/↓: Navigate | →: Expand | ←: Collapse | /: Search | p: Preview | q/Esc: Quit ";
253→        let help = Paragraph::new(help_text).style(Style::default().fg(Color::Cyan));
254→        frame.render_widget(help, help_area);
255→    }
