258→fn render_preview_pane(frame: &mut Frame, area: Rect, app: &mut App) {
259→    let block = Block::default()
260→        .borders(Borders::ALL)
261→        .title(" Preview ");
262→
263→    if let Some(ref error) = app.preview_error {
264→        let paragraph = Paragraph::new(error.as_str())
265→            .style(Style::default().fg(Color::Red))
266→            .block(block);
267→        frame.render_widget(paragraph, area);
268→    } else if let Some(ref mut protocol) = app.preview_image {
269→        let inner = block.inner(area);
270→        frame.render_widget(block, area);
271→        let image = StatefulImage::new(None);
272→        frame.render_stateful_widget(image, inner, protocol);
273→    } else {
274→        let paragraph = Paragraph::new("Decoding...")
275→            .style(Style::default().fg(Color::DarkGray))
276→            .block(block);
277→        frame.render_widget(paragraph, area);
278→    }
