281→fn render_validation_pane(frame: &mut Frame, area: Rect, app: &App) {
282→    let sop_class_text = match &app.sop_class {
283→        SopClass::Ct => "CT Image Storage",
284→        SopClass::Mr => "MR Image Storage",
285→        SopClass::Other(_) => "Other",
286→        SopClass::Unknown => "Unknown",
287→    };
288→
289→    let sop_class_uid = match &app.sop_class {
290→        SopClass::Ct => "1.2.840.10008.5.1.4.1.1.2",
291→        SopClass::Mr => "1.2.840.10008.5.1.4.1.1.4",
292→        SopClass::Other(uid) => uid.as_str(),
293→        SopClass::Unknown => "N/A",
294→    };
295→
296→    let (title, border_color) = match &app.validation_result {
297→        ValidationResult::Valid => (" ✓ All required fields present ", Color::Blue),
298→        ValidationResult::Invalid(_) => (" ✗ Missing required fields ", Color::Red),
299→        ValidationResult::NotApplicable => (" Validation not applicable ", Color::DarkGray),
300→    };
301→
302→    let mut lines = vec![Line::from(vec![Span::raw(format!(
303→        "SOP Class: {} ({})",
304→        sop_class_text, sop_class_uid
305→    ))])];
306→
307→    if let ValidationResult::Invalid(missing) = &app.validation_result {
308→        let missing_text = missing.join(", ");
309→        lines.push(Line::from(vec![
310→            Span::styled("Missing:   ", Style::default().fg(Color::Red)),
311→            Span::styled(
312→                missing_text,
313→                Style::default().fg(Color::Red).add_modifier(Modifier::BOLD),
314→            ),
315→        ]));
316→    }
317→
318→    let paragraph = Paragraph::new(lines).block(
319→        Block::default()
320→            .borders(Borders::ALL)
321→            .border_style(Style::default().fg(border_color))
322→            .title(title)
323→            .title_style(Style::default().fg(border_color)),
324→    );
325→
326→    frame.render_widget(paragraph, area);
327→}
