 17→/// DICOM TUI Viewer - View DICOM file tags in a terminal interface
 18→#[derive(Parser, Debug)]
 19→#[command(author, version, about, long_about = None)]
 20→struct Args {
 21→    /// Compare two DICOM files (baseline vs modified)
 22→    #[arg(short = 'd', long, value_names = ["BASELINE", "MODIFIED"], num_args = 2)]
 23→    diff: Option<Vec<PathBuf>>,
 24→
 25→    /// Path to the DICOM file to view (used when --diff is not specified)
 26→    #[arg(value_name = "FILE", required_unless_present = "diff")]
 27→    file: Option<PathBuf>,
 28→}
 29→
 30→fn main() -> Result<(), Box<dyn std::error::Error>> {
 31→    let args = Args::parse();
 32→
 33→    let picker = Picker::from_query_stdio().ok();
 34→
 35→    let (tags, file_name, modified_name, validation_result, sop_class, diff_mode, dicom_file_path) =
 36→        if let Some(diff_files) = &args.diff {
 37→            if diff_files.len() != 2 {
 38→                return Err("--diff requires exactly two file arguments".into());
 39→            }
 40→            let baseline_path = &diff_files[0];
 41→            let modified_path = &diff_files[1];
 42→
 43→            let tags = dicom::compare_dicom_files(baseline_path, modified_path)?;
 44→
 45→            let baseline_name = baseline_path
 46→                .file_name()
 47→                .map(|s| s.to_string_lossy().to_string())
 48→                .unwrap_or_else(|| baseline_path.to_string_lossy().to_string());
 49→            let modified_name = modified_path
 50→                .file_name()
 51→                .map(|s| s.to_string_lossy().to_string())
 52→                .unwrap_or_else(|| modified_path.to_string_lossy().to_string());
 53→
 54→            let sop_class =
 55→                validation::get_sop_class(baseline_path).unwrap_or(validation::SopClass::Unknown);
 56→            let validation_result = validation::validate_type1_fields(baseline_path)
 57→                .unwrap_or(validation::ValidationResult::NotApplicable);
 58→
 59→            (
 60→                tags,
 61→                baseline_name,
 62→                Some(modified_name),
 63→                validation_result,
 64→                sop_class,
 65→                true,
 66→                Some(baseline_path.clone()),
 67→            )
 68→        } else {
 69→            let file = args
 70→                .file
 71→                .ok_or("Either --diff with two files or a single file argument is required")?;
 72→
 73→            let obj = ::dicom::object::open_file(&file)?;
 74→            let tags = dicom::extract_tags(&obj);
 75→            let sop_class = validation::get_sop_class_from_obj(&obj);
 76→            let validation_result = validation::validate_type1_fields_from_obj(&obj);
 77→
 78→            let file_name = file
 79→                .file_name()
 80→                .map(|s| s.to_string_lossy().to_string())
 81→                .unwrap_or_else(|| file.to_string_lossy().to_string());
 82→
 83→            (
 84→                tags,
 85→                file_name,
 86→                None,
 87→                validation_result,
 88→                sop_class,
 89→                false,
 90→                Some(file),
 91→            )
 92→        };
 93→
 94→    let mut app = App::new_with_diff(
 95→        tags,
 96→        file_name,
 97→        modified_name,
 98→        validation_result,
 99→        sop_class,
100→        diff_mode,
101→        dicom_file_path,
102→        picker,
103→    );
104→
105→    enable_raw_mode()?;
106→    let mut stdout = io::stdout();
107→    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
108→    let backend = CrosstermBackend::new(stdout);
109→    let mut terminal = Terminal::new(backend)?;
110→
111→    let result = run_app(&mut terminal, &mut app);
112→
113→    disable_raw_mode()?;
114→    execute!(
115→        terminal.backend_mut(),
116→        LeaveAlternateScreen,
117→        DisableMouseCapture
118→    )?;
119→    terminal.show_cursor()?;
120→
121→    if let Err(err) = result {
122→        eprintln!("Error: {}", err);
123→        return Err(err.into());
124→    }
125→
126→    Ok(())
127→}
128→
129→fn run_app<B: Backend>(terminal: &mut Terminal<B>, app: &mut App) -> io::Result<()> {
130→    loop {
131→        terminal.draw(|frame| ui::render(frame, app))?;
132→
133→        app.handle_events()?;
134→
135→        if app.should_quit {
136→            return Ok(());
137→        }
138→    }
139→}
